  ('elementary-0489de64-moex-00822', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關大眾捷運系統運價率計算公式之行政程序的敘述，何者正確？', '["大眾捷運系統運價率之計算公式，由中央主管機關擬訂，報請行政院核定；變更時亦同", "大眾捷運系統運價率之計算公式，由中央主管機關擬訂，報請立法院核定；變更時亦同", "大眾捷運系統運價率之計算公式，由地方主管機關擬訂，報請交通部核定；變更時亦同", "大眾捷運系統運價率之計算公式，由地方主管機關擬訂，報請地方議會核定；變更時亦同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00823', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '主管機關對大眾運輸之營運及服務應定期辦理評鑑；其評鑑對象、方式、項目與標準、成績評定、成果 運用、公告程序及獎勵基準等事項之辦法，由中央主管機關定之。其法源為：', '["大眾捷運法", "公路法", "發展大眾運輸條例", "促進大眾運輸發展方案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00824', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '公路法規定，公路主管機關為公路養護、修建及安全管理所需經費，得徵收：', '["使用牌照稅", "汽車燃料使用費", "燃油附加費", "空氣污染防制費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00825', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關民用航空運輸業客貨運價訂定與使用等規定之敘述，何者錯誤？', '["民用航空運輸業客貨運價，其為國際定期航線者，應報請交通部民航局轉報交通部核備", "民用航空運輸業客貨運價，其為國際定期航線者，應報請交通部民航局轉報交通部備查", "民用航空運輸業客貨運價，其為國內定期航線者，應報請交通部民航局轉報交通部核准其上、下限範圍", "民用航空運輸業客貨運價之使用、優惠方式、報核程序及生效日期等相關事項之管理辦法，由交通部 定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00826', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '停車場法規定，路邊停車場及公有路外公共停車場之收費，應依：', '["區位、車種、時段之不同，訂定差別費率", "區域、流量、時段之不同，訂定差別費率", "區位、車型、時段之不同，訂定差別費率", "區位、車種、身分之不同，訂定差別費率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00827', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列何者不屬於道路交通管理處罰條例所指「慢車」範疇？', '["腳踏自行車", "電動自行車", "機車", "獸力行駛車輛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00828', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關鐵路法之敘述，何者錯誤？', '["鐵路以國營為原則。地方營、民營及專用鐵路之興建、延長、移轉或經營，應經交通部核准", "國營鐵路，由交通部經營。地方營、民營及專用鐵路，由交通部管理", "鐵路軌距，定為一公尺四公寸三公分五公釐。但有特別情事，經交通部核准者，不在此限", "國營鐵路運價率之計算公式，由交通部擬訂，報請行政院送請立法院審定之；變更時亦同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00829', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依違反道路交通管理事件統一裁罰標準及處理細則規定，「違反道路交通管理事件行為人得於應到案時 間內，以郵局匯票、郵政劃撥、信用卡轉帳、電話語音轉帳，……」，係行政機關（構）間之：', '["聯合關係", "職務協助關係", "委託關係", "委辦關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00830', 'elementary-0489de64', 'elementary-0489de64-moex-110-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '以執行政策為任務或依法執行職務在各級政府機關組織法規中，定有職稱及官等之永業性人員，一般稱 之為：', '["政務人員", "常務人員", "公營事業人員", "常任人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:02+00:00", "source_pdf_sha1": "cabfdd2fe12a", "answer_pdf_sha1": "9155c444100e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "513", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
